<?php
require_once __DIR__ . '/models/WorkoutPlanModel.php'; require_once __DIR__ . '/models/Database.php';
$id=(int)($_GET['id']??0); $model = new WorkoutPlanModel(); $plan=$model->getById($id); if(!$plan){ die('Invalid ID'); }
$db = Database::getInstance()->getConnection(); $users=$db->query('SELECT * FROM users')->fetchAll(); $goals=$db->query('SELECT * FROM plan_goals')->fetchAll(); $levels=$db->query('SELECT * FROM plan_levels')->fetchAll(); $exercises=$db->query('SELECT * FROM exercises')->fetchAll();
$selected=array_map(fn($r)=>(int)$r['id'],$model->getExercisesForPlan($id));
if($_SERVER['REQUEST_METHOD']==='POST'){ $data=['title'=>trim($_POST['title']),'note'=>trim($_POST['note']),'user_id'=>(int)$_POST['user_id'],'goal_id'=>(int)$_POST['goal_id'],'level_id'=>(int)$_POST['level_id'],'is_active'=>isset($_POST['is_active'])?1:0]; $model->update($id,$data); $model->syncExercises($id,$_POST['exercise_ids']??[]); header('Location: /workout-plan-detail.php?id='.$id); exit; }
?><!doctype html><html><body><?php include __DIR__ . '/includes/nav.php'; ?><h1>Edit workout plan</h1><form method="post"><input name="title" value="<?= htmlspecialchars($plan['title']); ?>" required><br><textarea name="note"><?= htmlspecialchars($plan['note']); ?></textarea><br><select name="user_id"><?php foreach($users as $u): ?><option value="<?= $u['id']; ?>" <?= $plan['user_id']==$u['id']?'selected':''; ?>><?= htmlspecialchars($u['name']); ?></option><?php endforeach;?></select><select name="goal_id"><?php foreach($goals as $g): ?><option value="<?= $g['id']; ?>" <?= $plan['goal_id']==$g['id']?'selected':''; ?>><?= htmlspecialchars($g['name']); ?></option><?php endforeach;?></select><select name="level_id"><?php foreach($levels as $l): ?><option value="<?= $l['id']; ?>" <?= $plan['level_id']==$l['id']?'selected':''; ?>><?= htmlspecialchars($l['name']); ?></option><?php endforeach;?></select><br><?php foreach($exercises as $e): ?><label><input type="checkbox" name="exercise_ids[]" value="<?= $e['id']; ?>" <?= in_array((int)$e['id'],$selected,true)?'checked':''; ?>><?= htmlspecialchars($e['name']); ?></label><?php endforeach; ?><br><label><input type="checkbox" name="is_active" <?= $plan['is_active']?'checked':''; ?>>Active</label><button>Update</button></form></body></html>
